#define RING_BUF_SIZE 256 // must be power of 2
typedef struct {
    volatile uint8_t buf[RING_BUF_SIZE];
    volatile uint16_t head; // write index (ISR)
    volatile uint16_t tail; // read index (task)
} RingBuf_t;

static RingBuf_t rx_ring = {0};

// In UART ISR:
void USART2_IRQHandler(void) {
    if (USART2->SR & USART_SR_RXNE) {
        uint16_t next = (rx_ring.head + 1) & (RING_BUF_SIZE - 1);
        if (next != rx_ring.tail) { // not full
            rx_ring.buf[rx_ring.head] = USART2->DR;
            rx_ring.head = next;
        }
    }
}

// In task:
int ring_read(uint8_t *byte) {
    if (rx_ring.tail == rx_ring.head) return 0; // empty
    *byte = rx_ring.buf[rx_ring.tail];
    rx_ring.tail = (rx_ring.tail + 1) & (RING_BUF_SIZE - 1);
    return 1;
}
```
Power-of-2 size enables fast modulo via bitmask. No mutex needed if single producer (ISR) and single consumer (task).
